import { z } from 'zod';
import logger from '../logger.js';

export const trimAndRequire = (message) =>
  z
    .string()
    .trim()
    .min(1, message);

export const numericString = (message) =>
  z
    .string()
    .trim()
    .regex(/^\d+$/, message);

export const phoneNumberSchema = (numericMessage, lengthMessage) =>
  numericString(numericMessage).superRefine((val, ctx) => {
    if (val.length < 7 || val.length > 15) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: lengthMessage,
      });
    }
  });

export const mapFieldErrors = (error) =>
  error.issues.reduce(
    (acc, issue) => {
      const [path] = issue.path;
      if (typeof path === 'string') {
        if (!acc[path]) {
          acc[path] = issue.message;
        }
      } else if (!acc._form) {
        acc._form = issue.message;
      }
      return acc;
    },
    /** @type {Record<string, string>} */ ({})
  );

/**
 * Maps invoice validation errors, separating form errors from item errors
 * @param {z.ZodError} error - Zod validation error
 * @returns {Object} Object with formErrors and itemErrors
 */
export const mapInvoiceErrors = (error) => {
  const formErrors = {};
  const itemErrors = {};
  
  error.issues.forEach(issue => {
    const path = issue.path;
    
    // Handle item errors
    if (path.length >= 3 && path[0] === 'items' && typeof path[1] === 'number') {
      // Item field errors (e.g., items.0.description)
      const itemIndex = path[1];
      const field = path[2];
      itemErrors[`items.${itemIndex}.${field}`] = issue.message;
    } else if (path.length === 1 && path[0] === 'items') {
      // Array-level errors (e.g., "at least one item required")
      if (!itemErrors._items) {
        itemErrors._items = issue.message;
      }
    } else if (path.length > 0) {
      // Form field errors - use the first path element as the field name
      const fieldName = path[0];
      if (typeof fieldName === 'string' && fieldName !== '_form') {
        if (!formErrors[fieldName]) {
          formErrors[fieldName] = issue.message;
        }
      } else if (!formErrors._form) {
        formErrors._form = issue.message;
      }
    } else {
      // No path - general form error
      if (!formErrors._form) {
        formErrors._form = issue.message;
      }
    }
  });
  
  return { formErrors, itemErrors };
};

/**
 * Validates invoice data and handles error display
 * @param {Object} invoiceData - Invoice data to validate
 * @param {z.ZodSchema} validationSchema - Zod validation schema
 * @param {Function} setFormErrors - State setter for form errors
 * @param {Function} setItemErrors - State setter for item errors
 * @param {Function} showError - Function to show error toast
 * @param {Function} t - Translation function
 * @returns {Object} { success: boolean, data?: Object }
 */
/**
 * Maps field names to user-friendly labels
 */
const getFieldLabel = (fieldName, t) => {
  const fieldMap = {
    firstName: t('firstName', { ns: 'invoicing', defaultValue: 'First name' }),
    lastName: t('lastName', { ns: 'invoicing', defaultValue: 'Last name' }),
    customerEmail: t('customerEmail', { ns: 'invoicing', defaultValue: 'Customer Email' }),
    customerPhone: t('customerPhone', { ns: 'invoicing', defaultValue: 'Customer Phone Number' }),
    customerPhoneCountryCode: t('phoneNumber', { ns: 'invoicing', defaultValue: 'Phone Country Code' }),
    payee_note: t('payeeNote', { ns: 'invoicing', defaultValue: 'Payee note' }),
    description: t('description', { ns: 'invoicing', defaultValue: 'Description' }),
    provider: t('provider', { ns: 'invoicing', defaultValue: 'Provider' }),
    currency: t('currency', { ns: 'invoicing', defaultValue: 'Currency' }),
    items: t('items', { ns: 'invoicing', defaultValue: 'Invoice Items' }),
    taxAmount: t('taxAmount', { ns: 'invoicing', defaultValue: 'Tax Amount' }),
  };
  
  return fieldMap[fieldName] || fieldName;
};

export const validateInvoiceForm = (
  invoiceData,
  validationSchema,
  setFormErrors,
  setItemErrors,
  showError,
  t
) => {
  try {
  const result = validationSchema.safeParse(invoiceData);

  if (!result.success) {
    const { formErrors, itemErrors: itemErrs } = mapInvoiceErrors(result.error);
      
      // Set errors immediately - create new object references so React detects the change
      const formErrorsCopy = Object.keys(formErrors).length > 0 ? { ...formErrors } : {};
      const itemErrorsCopy = Object.keys(itemErrs).length > 0 ? { ...itemErrs } : {};
      
      // Set errors - React will update the UI
      setFormErrors(formErrorsCopy);
      setItemErrors(itemErrorsCopy);

      // Debug: Log errors being set
      logger.debug('Setting form errors', { formErrors: formErrorsCopy, itemErrors: itemErrorsCopy });

      // Collect all error messages and field names for better user feedback
      const fieldNamesWithErrors = [];
      const allErrors = [];

      // Collect form field errors
      Object.keys(formErrors).forEach(fieldName => {
        if (formErrors[fieldName]) {
          const label = getFieldLabel(fieldName, t);
          fieldNamesWithErrors.push(label);
          allErrors.push(formErrors[fieldName]);
        }
      });

      // Collect item errors
      const itemErrorFields = new Set();
      Object.keys(itemErrs).forEach(errorKey => {
        if (itemErrs[errorKey] && errorKey !== '_items') {
          // Extract field name from error key like "items.0.description"
          const match = errorKey.match(/items\.\d+\.(\w+)/);
          if (match) {
            const itemFieldName = match[1];
            const itemFieldMap = {
              description: t('itemDescription', { ns: 'invoicing', defaultValue: 'Item Description' }),
              quantity: t('quantity', { ns: 'invoicing', defaultValue: 'Quantity' }),
              unitPrice: t('unitPrice', { ns: 'invoicing', defaultValue: 'Unit Price' }),
            };
            itemErrorFields.add(itemFieldMap[itemFieldName] || itemFieldName);
          }
          allErrors.push(itemErrs[errorKey]);
        } else if (errorKey === '_items' && itemErrs[errorKey]) {
          allErrors.push(itemErrs[errorKey]);
        }
      });

      // Add item field errors to the list
      if (itemErrorFields.size > 0) {
        fieldNamesWithErrors.push(...Array.from(itemErrorFields));
      }

      // Build error message with specific field names
    if (allErrors.length > 0) {
        let errorMessage;
        
        // Always show field names if we have them
        if (fieldNamesWithErrors.length > 0) {
          if (fieldNamesWithErrors.length === 1) {
            // Single field error - show field name with error
            errorMessage = `${fieldNamesWithErrors[0]}: ${allErrors[0]}`;
          } else {
            // Multiple errors - list the fields
            const fieldsList = fieldNamesWithErrors.slice(0, 5).join(', ');
            const moreFields = fieldNamesWithErrors.length > 5 
              ? ` ${t('andMore', { ns: 'invoicing', defaultValue: 'and more' })}`
              : '';
            errorMessage = `${t('pleaseFillFields', { ns: 'invoicing', defaultValue: 'Please fill the following fields' })}: ${fieldsList}${moreFields}`;
          }
        } else if (allErrors.length === 1) {
          // Single error but no field name - show the error message
          errorMessage = allErrors[0];
        } else {
          // Fallback
          errorMessage = `${t('fillAllFields', { ns: 'invoicing' })} (${allErrors.length} ${t('errorsFound', { ns: 'invoicing', defaultValue: 'errors found' })})`;
        }
        
        // Debug logging
        logger.debug('Validation errors', {
          formErrors,
          itemErrs,
          fieldNamesWithErrors,
          allErrors,
          errorMessage
        });
        
        // Ensure showError is called
        if (showError && typeof showError === 'function') {
      showError(errorMessage);
        } else {
          logger.error('showError is not a function', { showError });
        }
      
      // Scroll to first error field
      setTimeout(() => {
        const errorInputs = document.querySelectorAll('input[style*="borderColor"], select[style*="borderColor"], textarea[style*="borderColor"]');
        for (const input of errorInputs) {
          const style = input.getAttribute('style') || '';
          if (style.includes('var(--error)')) {
            input.scrollIntoView({ behavior: 'smooth', block: 'center' });
            input.focus();
            break;
          }
        }
      }, 100);
    } else {
        const defaultMessage = t('fillAllFields', { ns: 'invoicing' });
        if (showError && typeof showError === 'function') {
          showError(defaultMessage);
        }
    }
    
    return { success: false };
  }

  // Clear errors on success
  setFormErrors({});
  setItemErrors({});
  
  return { success: true, data: result.data };
  } catch (error) {
    logger.error('Validation error', { error });
    const errorMessage = t('fillAllFields', { ns: 'invoicing' });
    if (showError && typeof showError === 'function') {
      showError(errorMessage);
    }
    return { success: false };
  }
};


